SELECT * FROM coach_student_relations



            AND coach_id = #{request.params.coachId}


            AND student_id = #{request.params.studentId}


            AND status = #{request.params.status}



ORDER BY create_time DESC

SELECT csr.id, csr.coach_id, csr.student_id, csr.status, csr.create_time, COALESCE(coach.real_name, coach.username) AS coach_name, COALESCE(student.real_name, student.username) AS student_name, coach.coach_level, coach.achievements, campus.name AS campus_name FROM coach_student_relations csr LEFT JOIN users coach ON csr.coach_id = coach.id LEFT JOIN users student ON csr.student_id = student.id LEFT JOIN campus ON coach.campus_id = campus.id
AND csr.coach_id = #{request.params.coachId}
AND csr.student_id = #{request.params.studentId}
AND csr.status = #{request.params.status}
AND coach.campus_id = #{request.params.campusId}
ORDER BY csr.create_time DESC
